-- Drop any that collide with an existing facility (case-insensitive name + zip).
delete from _ga_import t using facilities f
  where lower(t.name) = lower(f.name) and coalesce(t.zip,'') = coalesce(f.zip,'');

insert into facilities (
  id, name, street, city, state, zip, accreditations, levels_of_care, specialties, populations_served,
  is_gated, is_faith_based, referral_contact, is_published, operator_type, levels_detail, payers_detail,
  main_phone, intake_line, detox_on_site, mat_on_site, co_occurring, priority_tier, specialty_programs,
  website, plan, plan_status, bd_notes
)
select id, name, street, city, state, zip, accreditations, levels_of_care, specialties, populations_served,
  is_gated, is_faith_based, referral_contact, is_published, operator_type, levels_detail, payers_detail,
  main_phone, intake_line, detox_on_site, mat_on_site, co_occurring, priority_tier, specialty_programs,
  website, plan, plan_status, bd_notes
from _ga_import;

